/// @brief ZVec C API error code enumeration
enum zvec_error_code_t {
  /// < Success
  ZVEC_OK(0),

  /// < Resource not found
  ZVEC_ERROR_NOT_FOUND(1),

  /// < Resource already exists
  ZVEC_ERROR_ALREADY_EXISTS(2),

  /// < Invalid argument
  ZVEC_ERROR_INVALID_ARGUMENT(3),

  /// < Permission denied
  ZVEC_ERROR_PERMISSION_DENIED(4),

  /// < Failed precondition
  ZVEC_ERROR_FAILED_PRECONDITION(5),

  /// < Resource exhausted
  ZVEC_ERROR_RESOURCE_EXHAUSTED(6),

  /// < Unavailable
  ZVEC_ERROR_UNAVAILABLE(7),

  /// < Internal error
  ZVEC_ERROR_INTERNAL_ERROR(8),

  /// < Unsupported operation
  ZVEC_ERROR_NOT_SUPPORTED(9),

  /// < Unknown error
  ZVEC_ERROR_UNKNOWN(10);

  final int value;
  const zvec_error_code_t(this.value);

  static zvec_error_code_t fromValue(int value) => switch (value) {
    0 => ZVEC_OK,
    1 => ZVEC_ERROR_NOT_FOUND,
    2 => ZVEC_ERROR_ALREADY_EXISTS,
    3 => ZVEC_ERROR_INVALID_ARGUMENT,
    4 => ZVEC_ERROR_PERMISSION_DENIED,
    5 => ZVEC_ERROR_FAILED_PRECONDITION,
    6 => ZVEC_ERROR_RESOURCE_EXHAUSTED,
    7 => ZVEC_ERROR_UNAVAILABLE,
    8 => ZVEC_ERROR_INTERNAL_ERROR,
    9 => ZVEC_ERROR_NOT_SUPPORTED,
    10 => ZVEC_ERROR_UNKNOWN,
    _ => throw ArgumentError('Unknown value for zvec_error_code_t: $value'),
  };
}

